\displaystyle{\begin{aligned}[t]
    \frac{1}{12} \div \left(-\frac{8}{9}\right)
        \amp = \frac{1}{12} \cdot \left(-\frac{9}{8}\right) \amp \hbox{We can divide the first denominator and the second numerator by 3.}\\
        \amp = \frac{1}{4 }\cdot\left(-\frac{3}{8}\right) \\
        \amp = -\frac{3}{32}
\end{aligned}
    }
